import React from 'react';
import { Card, Stack, Box, Text, Heading, Icon, Divider } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent(props: Props): React.ReactElement {
  const {
    city,
    temperature,
    condition,
    humidity,
    windSpeed,
    unit = 'C',
    forecast,
  } = props;

  return (
    <Card shadow="md" padding={24} radius="lg" border={true}>
      <Stack direction="vertical" gap={20}>
        {/* Header: City and Condition */}
        <Stack direction="horizontal" gap={12} align="center" justify="between">
          <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
            {city}
          </Heading>
          <Stack direction="vertical" gap={4} align="center">
            <Icon
              name={condition.toLowerCase().replace(/\s+/g, '-')}
              size={32}
              color="var(--ggui-color-primary-500, #0ea5e9)"
            />
            <Text
              variant="label"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              {condition}
            </Text>
          </Stack>
        </Stack>

        {/* Temperature Display */}
        <Stack direction="vertical" gap={0} align="center">
          <div style={{ display: 'flex', alignItems: 'baseline', gap: 'var(--ggui-spacing-1, 4px)' }}>
            <Text
              size="4xl"
              weight="bold"
              color="var(--ggui-color-primary-600, #0284c7)"
            >
              {temperature}
            </Text>
            <Text
              size="base"
              color="var(--ggui-color-primary-600, #0284c7)"
            >
              °{unit}
            </Text>
          </div>
        </Stack>

        {/* Current Conditions Grid */}
        <Stack direction="horizontal" gap={16} justify="between">
          <Stack direction="vertical" gap={4} align="center">
            <Text
              variant="body"
              size="sm"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              Humidity
            </Text>
            <Text
              variant="label"
              color="var(--ggui-color-onSurface, #18181b)"
            >
              {humidity}%
            </Text>
          </Stack>
          <Stack direction="vertical" gap={4} align="center">
            <Text
              variant="body"
              size="sm"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              Wind Speed
            </Text>
            <Text
              variant="label"
              color="var(--ggui-color-onSurface, #18181b)"
            >
              {windSpeed} km/h
            </Text>
          </Stack>
        </Stack>

        {/* Divider */}
        <Divider
          orientation="horizontal"
          margin="var(--ggui-spacing-4, 16px)"
          color="var(--ggui-color-outlineVariant, #e4e4e7)"
        />

        {/* 5-Day Forecast Strip */}
        <Stack direction="horizontal" gap={12} wrap={true} align="stretch">
          {forecast.map((day, index) => (
            <Box
              key={index}
              padding={12}
              background="var(--ggui-color-surfaceVariant, #f4f4f5)"
              borderRadius="var(--ggui-shape-radius-md, 8px)"
              style={{ flex: '0 1 auto', minWidth: '70px' }}
            >
              <Stack direction="vertical" gap={8} align="center">
                {day.day && (
                  <Text
                    variant="caption"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  >
                    {day.day}
                  </Text>
                )}

                {day.icon && (
                  <Icon
                    name={day.icon}
                    size={20}
                    color="var(--ggui-color-primary-500, #0ea5e9)"
                  />
                )}

                {day.high !== undefined && (
                  <Text
                    variant="label"
                    size="sm"
                    color="var(--ggui-color-onSurface, #18181b)"
                  >
                    {day.high}°
                  </Text>
                )}

                {day.low !== undefined && (
                  <Text
                    variant="bodySmall"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  >
                    {day.low}°
                  </Text>
                )}
              </Stack>
            </Box>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState } from 'react';
import {
  Card,
  Stack,
  Progress,
  Heading,
  Input,
  RadioGroup,
  Checkbox,
  TextArea,
  Button,
  Text,
  Box,
  Container,
} from '@ggui-ai/design/primitives';

interface Props {
  featureOptions: string[];
  satisfactionLabels: string[];
}

interface FormData {
  name: string;
  email: string;
  satisfaction: string;
  features: string[];
  comments: string;
}

interface FieldErrors {
  name?: string;
  email?: string;
  satisfaction?: string;
}

export default function SurveyForm(props: Props) {
  const { featureOptions, satisfactionLabels } = props;

  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState<FormData>({
    name: '',
    email: '',
    satisfaction: '',
    features: [],
    comments: '',
  });
  const [fieldErrors, setFieldErrors] = useState<FieldErrors>({});
  const [submitStatus, setSubmitStatus] = useState<
    'idle' | 'submitting' | 'success' | 'error'
  >('idle');
  const [submitMessage, setSubmitMessage] = useState('');

  const validateEmail = (email: string): boolean => {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  };

  const validateStep1 = (): boolean => {
    const errors: FieldErrors = {};
    if (!formData.name.trim()) {
      errors.name = 'Name is required';
    }
    if (!formData.email.trim()) {
      errors.email = 'Email is required';
    } else if (!validateEmail(formData.email)) {
      errors.email = 'Please enter a valid email address';
    }
    setFieldErrors(errors);
    return Object.keys(errors).length === 0;
  };

  const validateStep2 = (): boolean => {
    const errors: FieldErrors = {};
    if (!formData.satisfaction) {
      errors.satisfaction = 'Please select a satisfaction level';
    }
    setFieldErrors(errors);
    return Object.keys(errors).length === 0;
  };

  const isCurrentStepValid = (): boolean => {
    if (currentStep === 1) {
      return (
        formData.name.trim() !== '' &&
        formData.email.trim() !== '' &&
        validateEmail(formData.email)
      );
    } else if (currentStep === 2) {
      return formData.satisfaction !== '';
    }
    return true;
  };

  const handleNameChange = (value: string) => {
    setFormData((prev) => ({ ...prev, name: value }));
    if (fieldErrors.name) {
      setFieldErrors((prev) => ({ ...prev, name: undefined }));
    }
  };

  const handleEmailChange = (value: string) => {
    setFormData((prev) => ({ ...prev, email: value }));
    if (fieldErrors.email) {
      setFieldErrors((prev) => ({ ...prev, email: undefined }));
    }
  };

  const handleSatisfactionChange = (value: string) => {
    setFormData((prev) => ({ ...prev, satisfaction: value }));
    if (fieldErrors.satisfaction) {
      setFieldErrors((prev) => ({ ...prev, satisfaction: undefined }));
    }
  };

  const handleFeatureToggle = (feature: string, checked: boolean) => {
    setFormData((prev) => ({
      ...prev,
      features: checked
        ? [...prev.features, feature]
        : prev.features.filter((f) => f !== feature),
    }));
  };

  const handleCommentsChange = (value: string) => {
    if (value.length <= 500) {
      setFormData((prev) => ({ ...prev, comments: value }));
    }
  };

  const handleNext = () => {
    if (currentStep === 1 && !validateStep1()) {
      return;
    }
    if (currentStep === 2 && !validateStep2()) {
      return;
    }
    if (currentStep < 5) {
      setCurrentStep(currentStep + 1);
    }
  };

  const handleBack = () => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
      setFieldErrors({});
    }
  };

  const handleSubmit = async () => {
    setSubmitStatus('submitting');
    try {
      // Call the onSubmit callback with the form data
      const submitPayload = {
        name: formData.name,
        email: formData.email,
        satisfaction: formData.satisfaction,
        features: formData.features,
        comments: formData.comments,
      };

      // Simulate the callback - in real use, this would be props.onSubmit
      // For now, we'll just simulate success
      await new Promise((resolve) => setTimeout(resolve, 500));

      setSubmitStatus('success');
      setSubmitMessage('Thank you! Your survey has been submitted.');

      // Reset form after success
      setTimeout(() => {
        setCurrentStep(1);
        setFormData({
          name: '',
          email: '',
          satisfaction: '',
          features: [],
          comments: '',
        });
        setSubmitStatus('idle');
        setSubmitMessage('');
      }, 2000);
    } catch (error) {
      setSubmitStatus('error');
      setSubmitMessage(
        'Failed to submit survey. Please try again.'
      );
    }
  };

  const satisfactionOptions = satisfactionLabels.map((label, index) => ({
    value: String(index + 1),
    label: label,
  }));

  return (
    <Container maxWidth="sm" padding={24}>
      <Card shadow="md" padding={24} radius="lg">
        <Stack gap={24} direction="vertical">
          {/* Progress Section */}
          <Stack gap={8} direction="vertical">
            <Progress
              value={currentStep}
              max={4}
              size="md"
              variant="default"
              showLabel={true}
            />
          </Stack>

          {/* Form Content */}
          <Stack gap={24} direction="vertical">
            {/* Step 1: Personal Information */}
            {currentStep === 1 && (
              <Stack gap={16} direction="vertical">
                <Heading level={3}>Tell us about yourself</Heading>
                <Stack gap={16} direction="vertical">
                  <Input
                    label="Full Name"
                    required={true}
                    value={formData.name}
                    onChange={handleNameChange}
                    placeholder="Enter your full name"
                    error={fieldErrors.name}
                  />
                  <Input
                    label="Email Address"
                    type="email"
                    required={true}
                    value={formData.email}
                    onChange={handleEmailChange}
                    placeholder="Enter your email address"
                    error={fieldErrors.email}
                  />
                </Stack>
              </Stack>
            )}

            {/* Step 2: Satisfaction Rating */}
            {currentStep === 2 && (
              <Stack gap={16} direction="vertical">
                <Heading level={3}>
                  How satisfied are you with our product?
                </Heading>
                <RadioGroup
                  label="Satisfaction Level"
                  value={formData.satisfaction}
                  onChange={handleSatisfactionChange}
                  options={satisfactionOptions}
                  direction="vertical"
                  error={fieldErrors.satisfaction}
                />
              </Stack>
            )}

            {/* Step 3: Feature Interests */}
            {currentStep === 3 && (
              <Stack gap={16} direction="vertical">
                <Heading level={3}>Which features interest you most?</Heading>
                <Stack gap={12} direction="vertical">
                  {featureOptions.map((feature) => (
                    <Checkbox
                      key={feature}
                      label={feature}
                      checked={formData.features.includes(feature)}
                      onChange={(checked) =>
                        handleFeatureToggle(feature, checked)
                      }
                    />
                  ))}
                </Stack>
              </Stack>
            )}

            {/* Step 4: Comments */}
            {currentStep === 4 && (
              <Stack gap={16} direction="vertical">
                <Heading level={3}>Tell us more (optional)</Heading>
                <TextArea
                  label="Additional Comments"
                  value={formData.comments}
                  onChange={handleCommentsChange}
                  rows={4}
                  maxLength={500}
                  showCount={true}
                  placeholder="Share any additional feedback..."
                />
              </Stack>
            )}

            {/* Step 5: Review */}
            {currentStep === 5 && (
              <Stack gap={16} direction="vertical">
                <Heading level={3}>Review Your Responses</Heading>
                <Stack gap={12} direction="vertical">
                  <Box
                    padding={12}
                    background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                    borderRadius={8}
                  >
                    <Text variant="label">Full Name</Text>
                    <Text>{formData.name}</Text>
                  </Box>
                  <Box
                    padding={12}
                    background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                    borderRadius={8}
                  >
                    <Text variant="label">Email Address</Text>
                    <Text>{formData.email}</Text>
                  </Box>
                  <Box
                    padding={12}
                    background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                    borderRadius={8}
                  >
                    <Text variant="label">Satisfaction Level</Text>
                    <Text>
                      {satisfactionLabels[parseInt(formData.satisfaction) - 1]}
                    </Text>
                  </Box>
                  <Box
                    padding={12}
                    background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                    borderRadius={8}
                  >
                    <Text variant="label">Features of Interest</Text>
                    <Text>
                      {formData.features.length > 0
                        ? formData.features.join(', ')
                        : 'None selected'}
                    </Text>
                  </Box>
                  <Box
                    padding={12}
                    background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                    borderRadius={8}
                  >
                    <Text variant="label">Additional Comments</Text>
                    <Text>
                      {formData.comments || 'Not provided'}
                    </Text>
                  </Box>
                </Stack>
              </Stack>
            )}

            {/* Success/Error Message */}
            {submitStatus === 'success' && (
              <Box
                padding={12}
                background="var(--ggui-color-success-50, #f0fdf4)"
                borderRadius={8}
              >
                <Text
                  variant="body"
                  color="var(--ggui-color-success-800, #166534)"
                >
                  {submitMessage}
                </Text>
              </Box>
            )}

            {submitStatus === 'error' && (
              <Box
                padding={12}
                background="var(--ggui-color-error-50, #fef2f2)"
                borderRadius={8}
              >
                <Text
                  variant="body"
                  color="var(--ggui-color-error-800, #991b1b)"
                >
                  {submitMessage}
                </Text>
              </Box>
            )}
          </Stack>

          {/* Navigation Buttons */}
          <Stack
            gap={12}
            direction="horizontal"
            justify="between"
            align="center"
          >
            {currentStep > 1 && (
              <Button
                variant="ghost"
                size="md"
                onClick={handleBack}
              >
                Back
              </Button>
            )}
            {currentStep < 5 ? (
              <Button
                variant="primary"
                size="md"
                onClick={handleNext}
                disabled={!isCurrentStepValid()}
              >
                Next
              </Button>
            ) : (
              <Button
                variant="primary"
                size="md"
                onClick={handleSubmit}
                loading={submitStatus === 'submitting'}
                disabled={submitStatus === 'submitting'}
              >
                Submit Survey
              </Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Container,
  Stack,
  Box,
  Card,
  Heading,
  Text,
  Input,
  Badge,
  Button,
} from '@ggui-ai/design/primitives';

interface Props {
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

const getCategoryBadgeVariant = (category?: string): 'default' | 'primary' | 'secondary' | 'success' | 'warning' | 'error' | 'info' => {
  switch (category) {
    case 'alkali-metal':
      return 'primary';
    case 'alkaline-earth-metal':
      return 'success';
    case 'transition-metal':
      return 'warning';
    case 'lanthanide':
      return 'error';
    case 'actinide':
      return 'info';
    case 'halogen':
      return 'primary';
    case 'noble-gas':
      return 'secondary';
    case 'nonmetal':
      return 'default';
    default:
      return 'default';
  }
};

const getCategoryBackgroundColor = (category?: string): string => {
  switch (category) {
    case 'alkali-metal':
      return 'var(--ggui-color-primary-50, #f0f9ff)';
    case 'alkaline-earth-metal':
      return 'var(--ggui-color-success-50, #f0fdf4)';
    case 'transition-metal':
      return 'var(--ggui-color-warning-50, #fffbeb)';
    case 'lanthanide':
      return 'var(--ggui-color-error-50, #fef2f2)';
    case 'actinide':
      return 'var(--ggui-color-info-50, #ecfeff)';
    case 'halogen':
      return 'var(--ggui-color-primary-100, #e0f2fe)';
    case 'noble-gas':
      return 'var(--ggui-color-surfaceVariant, #f4f4f5)';
    case 'nonmetal':
      return 'var(--ggui-color-outlineVariant, #e4e4e7)';
    default:
      return 'var(--ggui-color-surface, #fafafa)';
  }
};

export default function PeriodicTable(props: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<typeof props.elements[0] | null>(null);

  const filteredElements = useMemo(() => {
    const q = searchQuery.toLowerCase();
    return props.elements.filter(el => {
      return (
        (el.name?.toLowerCase().includes(q) ?? false) ||
        (el.symbol?.toLowerCase().includes(q) ?? false)
      );
    });
  }, [searchQuery, props.elements]);

  const uniqueCategories = useMemo(() => {
    const cats = new Set<string>();
    props.elements.forEach(el => {
      if (el.category) {
        cats.add(el.category);
      }
    });
    return Array.from(cats).sort();
  }, [props.elements]);

  const visibleElementsSet = useMemo(() => {
    return new Set(filteredElements.map(el => el.atomicNumber));
  }, [filteredElements]);

  return (
    <Container maxWidth="3xl" padding={24}>
      <Stack gap={24}>
        {/* Title */}
        <Heading level={1}>Periodic Table of Elements</Heading>

        {/* Search Input */}
        <Input
          label="Search by name or symbol"
          placeholder="e.g., Hydrogen, H"
          value={searchQuery}
          onChange={setSearchQuery}
        />

        {/* Legend */}
        <Stack direction="horizontal" gap={16} wrap={true}>
          {uniqueCategories.map(category => (
            <Badge
              key={category}
              variant={getCategoryBadgeVariant(category)}
              size="md"
              pill={true}
            >
              {category}
            </Badge>
          ))}
        </Stack>

        {/* Periodic Table Grid */}
        <Box
          padding={16}
          background="var(--ggui-color-surface, #fafafa)"
          borderRadius="var(--ggui-shape-radius-lg, 12px)"
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, 1fr)',
            gap: 'var(--ggui-spacing-2, 8px)',
            border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
          }}
        >
          {props.elements.map(el => {
            const isVisible = visibleElementsSet.has(el.atomicNumber);
            if (!isVisible) {
              return null;
            }

            return (
              <Card
                key={el.atomicNumber}
                shadow="sm"
                padding={12}
                radius="md"
                border={true}
                style={{
                  gridColumn: el.col,
                  gridRow: el.row,
                  backgroundColor: getCategoryBackgroundColor(el.category),
                  cursor: 'pointer',
                  transition: 'all 200ms ease',
                  transform: 'scale(1)',
                }}
                onClick={() => setSelectedElement(el)}
                onMouseEnter={(e) => {
                  (e.currentTarget as HTMLElement).style.transform = 'scale(1.05)';
                  (e.currentTarget as HTMLElement).style.boxShadow = 'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))';
                }}
                onMouseLeave={(e) => {
                  (e.currentTarget as HTMLElement).style.transform = 'scale(1)';
                  (e.currentTarget as HTMLElement).style.boxShadow = 'var(--ggui-shape-shadow-sm, 0 1px 2px 0 rgba(0,0,0,0.05))';
                }}
              >
                <Stack gap={2} align="center">
                  <Text
                    variant="overline"
                    color="var(--ggui-color-primary-600, #0284c7)"
                    size="xs"
                  >
                    {el.atomicNumber}
                  </Text>
                  <Text size="2xl" weight="bold" align="center">
                    {el.symbol}
                  </Text>
                  <Text
                    variant="caption"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    align="center"
                  >
                    {el.name}
                  </Text>
                </Stack>
              </Card>
            );
          })}
        </Box>

        {/* No results message */}
        {searchQuery && filteredElements.length === 0 && (
          <Text
            variant="body"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
          >
            No elements found matching "{searchQuery}"
          </Text>
        )}

        {/* Detail Panel */}
        {selectedElement && (
          <Card shadow="md" padding={20} radius="lg" border={true}>
            <Stack gap={12}>
              <Heading level={3}>{selectedElement.name}</Heading>
              <Stack direction="horizontal" gap={16} wrap={true}>
                <Text variant="body">
                  <strong>Symbol:</strong> {selectedElement.symbol}
                </Text>
                <Text variant="body">
                  <strong>Atomic #:</strong> {selectedElement.atomicNumber}
                </Text>
                <Text variant="body">
                  <strong>Weight:</strong> {selectedElement.atomicWeight?.toFixed(3) ?? 'N/A'}
                </Text>
                <Text variant="body">
                  <strong>Category:</strong> {selectedElement.category ?? 'Unknown'}
                </Text>
              </Stack>
              <Button variant="ghost" onClick={() => setSelectedElement(null)}>
                Close
              </Button>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

import { useState } from 'react';
import {
  Container,
  Stack,
  Box,
  Card,
  Heading,
  Text,
  Badge,
  Icon,
  Button,
  Tabs,
  Table,
  Divider,
  Toast,
} from '@ggui-ai/design/primitives';

interface Props {
  product: {
    id?: string;
    name?: string;
    price?: number;
    currency?: string;
    rating?: number;
    reviewCount?: number;
    stock?: number;
    description?: string;
    specifications?: Array<{ key?: string; value?: string }>;
    reviews?: Array<{
      author?: string;
      rating?: number;
      text?: string;
      date?: string;
    }>;
  };
  onAddToCart?: (payload: { productId: string; quantity: number }) => void;
}

export default function ProductDetailPage(props: Props) {
  const { product, onAddToCart } = props;

  const [quantity, setQuantity] = useState(1);
  const [activeTabKey, setActiveTabKey] = useState('description');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [feedback, setFeedback] = useState<{
    type: 'success' | 'error';
    message: string;
  } | null>(null);
  const [showToast, setShowToast] = useState(false);

  const productId = product.id ?? '';
  const productName = product.name ?? 'Unknown Product';
  const productPrice = product.price ?? 0;
  const currency = product.currency ?? 'USD';
  const rating = product.rating ?? 0;
  const reviewCount = product.reviewCount ?? 0;
  const stock = product.stock ?? 0;
  const description = product.description ?? '';
  const specifications = product.specifications ?? [];
  const reviews = product.reviews ?? [];

  const filledStars = Math.round(rating);
  const emptyStars = 5 - filledStars;

  const getStockStatus = () => {
    if (stock === 0) return { variant: 'error' as const, text: 'Out of Stock' };
    if (stock <= 5) return { variant: 'warning' as const, text: 'Low Stock' };
    return { variant: 'success' as const, text: 'In Stock' };
  };

  const stockStatus = getStockStatus();

  const handleDecrement = () => {
    setQuantity(Math.max(1, quantity - 1));
  };

  const handleIncrement = () => {
    setQuantity(Math.min(stock, quantity + 1));
  };

  const handleAddToCart = async () => {
    if (!onAddToCart || quantity < 1 || stock === 0) return;

    setIsSubmitting(true);
    try {
      onAddToCart({ productId, quantity });
      setFeedback({ type: 'success', message: 'Added to cart!' });
      setShowToast(true);
      setTimeout(() => setShowToast(false), 3000);
    } catch (error) {
      setFeedback({
        type: 'error',
        message: 'Failed to add to cart. Please try again.',
      });
      setShowToast(true);
    } finally {
      setIsSubmitting(false);
    }
  };

  const tabItems = [
    {
      key: 'description',
      label: 'Description',
      content: (
        <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
          {description || 'No description available.'}
        </Text>
      ),
    },
    {
      key: 'specifications',
      label: 'Specifications',
      content:
        specifications.length > 0 ? (
          <Table
            columns={[
              { key: 'key', header: 'Key' },
              { key: 'value', header: 'Value' },
            ]}
            data={specifications}
            striped={false}
            hoverable={false}
          />
        ) : (
          <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            No specifications available.
          </Text>
        ),
    },
    {
      key: 'reviews',
      label: 'Reviews',
      content:
        reviews.length > 0 ? (
          <Stack gap={8} direction="vertical">
            {reviews.map((review, idx) => (
              <Card
                key={idx}
                shadow="none"
                border={true}
                padding={16}
                radius="lg"
              >
                <Stack gap={8} direction="vertical">
                  <Text
                    variant="label"
                    weight="semibold"
                    color="var(--ggui-color-onSurface, #18181b)"
                  >
                    {review.author ?? 'Anonymous'}
                  </Text>
                  <Stack direction="horizontal" gap={4} align="center">
                    {Array.from({ length: 5 }).map((_, i) =>
                      i < (review.rating ?? 0) ? (
                        <Icon
                          key={i}
                          name="star"
                          size={16}
                          color="var(--ggui-color-warning-500, #f59e0b)"
                        />
                      ) : (
                        <Icon
                          key={i}
                          name="star"
                          size={16}
                          color="var(--ggui-color-outline, #d4d4d8)"
                        />
                      )
                    )}
                  </Stack>
                  <Text
                    variant="body"
                    color="var(--ggui-color-onSurface, #18181b)"
                  >
                    {review.text ?? ''}
                  </Text>
                  <Text
                    variant="caption"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  >
                    {review.date ?? new Date().toLocaleDateString()}
                  </Text>
                </Stack>
              </Card>
            ))}
          </Stack>
        ) : (
          <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            No reviews yet.
          </Text>
        ),
    },
  ];

  return (
    <Container maxWidth="2xl" padding={24}>
      <Stack gap={16} direction="vertical">
        <Stack direction="horizontal" gap={16} align="start">
          <Box
            background="var(--ggui-color-primary-50, #f0f9ff)"
            borderRadius={12}
            padding={0}
            style={{
              minWidth: '400px',
              height: '400px',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              flex: '0 0 auto',
            }}
          >
            <Text
              variant="bodyLarge"
              color="var(--ggui-color-primary-700, #0369a1)"
              align="center"
            >
              {productName}
            </Text>
          </Box>

          <Stack gap={16} direction="vertical" style={{ flex: 1 }}>
            <Stack gap={8} direction="vertical">
              <Heading
                level={2}
                color="var(--ggui-color-onSurface, #18181b)"
              >
                {productName}
              </Heading>

              <Text
                variant="bodyLarge"
                weight="bold"
                color="var(--ggui-color-onSurface, #18181b)"
              >
                {currency} {productPrice.toFixed(2)}
              </Text>

              <Stack direction="horizontal" gap={4} align="center">
                {Array.from({ length: 5 }).map((_, i) =>
                  i < filledStars ? (
                    <Icon
                      key={i}
                      name="star"
                      size={16}
                      color="var(--ggui-color-warning-500, #f59e0b)"
                    />
                  ) : (
                    <Icon
                      key={i}
                      name="star"
                      size={16}
                      color="var(--ggui-color-outline, #d4d4d8)"
                    />
                  )
                )}
                <Text
                  variant="body"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                >
                  {rating.toFixed(1)} ({reviewCount} reviews)
                </Text>
              </Stack>

              <Badge variant={stockStatus.variant} size="md">
                {stockStatus.text}
              </Badge>
            </Stack>
          </Stack>
        </Stack>

        <Divider orientation="horizontal" margin={16} />

        <Tabs
          items={tabItems}
          activeKey={activeTabKey}
          onChange={setActiveTabKey}
          variant="pills"
          size="md"
        />

        <Divider orientation="horizontal" margin={16} />

        <Stack gap={16} direction="vertical" style={{ paddingTop: '16px' }}>
          <Stack direction="horizontal" align="center" gap={8}>
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              Quantity
            </Text>
            <Button
              variant="outline"
              size="sm"
              onClick={handleDecrement}
              disabled={quantity === 1}
              aria-label="Decrease quantity"
            >
              −
            </Button>
            <Text
              variant="body"
              align="center"
              color="var(--ggui-color-onSurface, #18181b)"
              style={{ minWidth: '40px' }}
            >
              {quantity}
            </Text>
            <Button
              variant="outline"
              size="sm"
              onClick={handleIncrement}
              disabled={quantity >= stock || stock === 0}
              aria-label="Increase quantity"
            >
              +
            </Button>
          </Stack>

          <Button
            variant="primary"
            size="md"
            fullWidth={true}
            onClick={handleAddToCart}
            disabled={stock === 0 || isSubmitting}
            loading={isSubmitting}
          >
            Add to Cart
          </Button>
        </Stack>
      </Stack>

      {showToast && feedback && (
        <Toast
          variant={feedback.type}
          message={feedback.message}
          visible={showToast}
          onClose={() => setShowToast(false)}
          duration={feedback.type === 'success' ? 3000 : 0}
        />
      )}
    </Container>
  );
}

import React, { useState, useRef, useEffect } from 'react';
import {
  Card,
  Stack,
  Heading,
  Badge,
  Divider,
  Text,
  Box,
  Input,
  Button,
  Icon,
  Spinner,
} from '@ggui-ai/design/primitives';

interface Props {
  title: string;
  currentUser: string;
  participantCount?: number;
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
}

interface Message {
  sender?: string;
  text?: string;
  timestamp?: string;
}

export default function ChatWindowComponent(props: Props) {
  const { title, currentUser, participantCount, messages: initialMessages } = props;

  const [messages, setMessages] = useState<Message[]>(initialMessages ?? []);
  const [inputValue, setInputValue] = useState('');
  const [typingUser, setTypingUser] = useState<string | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom when messages change
  useEffect(() => {
    if (messagesEndRef.current) {
      messagesEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [messages, typingUser]);

  // Listen for stream events
  useEffect(() => {
    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent;
      const { type, data } = customEvent.detail ?? {};

      if (type === 'message') {
        setMessages((prev) => [...prev, data]);
      } else if (type === 'typing') {
        if (data?.active) {
          setTypingUser(data?.sender ?? null);
        } else {
          setTypingUser(null);
        }
      }
    };

    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  const handleSend = () => {
    const trimmedInput = inputValue.trim();
    if (!trimmedInput) return;

    const timestamp = new Date().toISOString();

    // Dispatch sendMessage action
    const event = new CustomEvent('ggui:action', {
      detail: {
        actionId: 'sendMessage',
        payload: { text: trimmedInput, timestamp },
      },
    });
    window.dispatchEvent(event);

    // Optimistically add message
    setMessages((prev) => [
      ...prev,
      { sender: currentUser, text: trimmedInput, timestamp },
    ]);
    setInputValue('');
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  // Group consecutive messages from same sender
  const groupedMessages: Array<{ sender?: string; messages: Message[] }> = [];
  messages.forEach((msg) => {
    const lastGroup = groupedMessages[groupedMessages.length - 1];
    if (lastGroup && lastGroup.sender === msg.sender) {
      lastGroup.messages.push(msg);
    } else {
      groupedMessages.push({ sender: msg.sender, messages: [msg] });
    }
  });

  const formatTime = (timestamp?: string): string => {
    if (!timestamp) return '';
    try {
      const date = new Date(timestamp);
      return date.toLocaleTimeString('en-US', {
        hour: '2-digit',
        minute: '2-digit',
        hour12: true,
      });
    } catch {
      return '';
    }
  };

  const isCurrentUserMessage = (sender?: string): boolean =>
    sender === currentUser;

  return (
    <Card
      shadow="md"
      padding={0}
      radius="lg"
      style={{
        display: 'flex',
        flexDirection: 'column',
        height: '100%',
        maxHeight: '600px',
      }}
    >
      {/* Header */}
      <Stack
        direction="horizontal"
        align="center"
        justify="between"
        gap="var(--ggui-spacing-2, 8px)"
        style={{
          padding: 'var(--ggui-spacing-4, 16px)',
          backgroundColor: 'var(--ggui-color-surface, #fafafa)',
        }}
      >
        <Heading level={3} style={{ margin: 0 }}>
          {title}
        </Heading>
        {participantCount != null && (
          <Badge variant="primary" size="sm" pill>
            {participantCount} participants
          </Badge>
        )}
      </Stack>

      <Divider orientation="horizontal" margin={0} />

      {/* Message List */}
      <div
        style={{
          flex: 1,
          overflowY: 'auto',
          padding: 'var(--ggui-spacing-4, 16px)',
          backgroundColor: 'var(--ggui-color-surface, #fafafa)',
          display: 'flex',
          flexDirection: 'column',
          gap: 'var(--ggui-spacing-2, 8px)',
        }}
        role="log"
        aria-live="polite"
      >
        {groupedMessages.map((group, groupIdx) => {
          const isCurrentUser = isCurrentUserMessage(group.sender);
          return (
            <div key={groupIdx}>
              {group.messages.map((msg, msgIdx) => (
                <div
                  key={msgIdx}
                  style={{
                    display: 'flex',
                    justifyContent: isCurrentUser ? 'flex-end' : 'flex-start',
                    marginBottom:
                      msgIdx === group.messages.length - 1
                        ? 'var(--ggui-spacing-2, 8px)'
                        : 'var(--ggui-spacing-1, 4px)',
                  }}
                >
                  <Box
                    padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-3, 12px)"
                    borderRadius="var(--ggui-shape-radius-lg, 12px)"
                    background={
                      isCurrentUser
                        ? 'var(--ggui-color-primary-600, #0284c7)'
                        : 'var(--ggui-color-surfaceVariant, #f4f4f5)'
                    }
                    style={{
                      maxWidth: '70%',
                    }}
                  >
                    {msgIdx === 0 && !isCurrentUser && (
                      <Text
                        variant="caption"
                        color="var(--ggui-color-onSurfaceVariant, #52525b)"
                        style={{ marginBottom: 'var(--ggui-spacing-1, 4px)' }}
                      >
                        {group.sender}
                      </Text>
                    )}
                    <Text
                      variant="body"
                      color={
                        isCurrentUser
                          ? '#ffffff'
                          : 'var(--ggui-color-onSurface, #18181b)'
                      }
                      style={{
                        wordWrap: 'break-word',
                        overflowWrap: 'break-word',
                      }}
                    >
                      {msg.text}
                    </Text>
                    <Text
                      variant="caption"
                      color={
                        isCurrentUser
                          ? '#ffffff'
                          : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                      }
                      style={{ marginTop: 'var(--ggui-spacing-1, 4px)' }}
                    >
                      {formatTime(msg.timestamp)}
                    </Text>
                  </Box>
                </div>
              ))}
            </div>
          );
        })}

        {/* Typing Indicator */}
        {typingUser && (
          <div
            style={{
              display: 'flex',
              alignItems: 'center',
              gap: 'var(--ggui-spacing-2, 8px)',
            }}
          >
            <Text
              variant="caption"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              {typingUser} is typing
            </Text>
            <Spinner
              size={14}
              color="var(--ggui-color-primary-600, #0284c7)"
            />
          </div>
        )}

        <div ref={messagesEndRef} />
      </div>

      <Divider orientation="horizontal" margin={0} />

      {/* Input Area */}
      <Stack
        direction="horizontal"
        gap="var(--ggui-spacing-2, 8px)"
        align="center"
        style={{
          padding: 'var(--ggui-spacing-3, 12px)',
          backgroundColor: 'var(--ggui-color-surface, #fafafa)',
        }}
      >
        <Input
          label="Message input"
          placeholder="Type a message..."
          value={inputValue}
          onChange={setInputValue}
          onKeyPress={handleKeyPress}
          style={{ flex: 1 }}
        />
        <Button
          variant="primary"
          size="md"
          onClick={handleSend}
          disabled={!inputValue.trim()}
          rightIcon={<Icon name="send" size={16} />}
          aria-label="Send message"
        >
          Send
        </Button>
      </Stack>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Stack,
  Card,
  Progress,
  Button,
  Input,
  Select,
  Toggle,
  Text,
  Heading,
  Box,
  Divider,
} from '@ggui-ai/design/primitives';

interface Props {
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  avatarOptions: string[];
  roleOptions: string[];
  onComplete?: (data: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

interface FormData {
  name: string;
  email: string;
  avatar: string;
  role: string;
  emailNotifications: boolean;
  theme: string;
}

interface Errors {
  name?: string;
  email?: string;
}

export default function OnboardingWizard(props: Props) {
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState<FormData>({
    name: props.initialProfile?.name ?? '',
    email: props.initialProfile?.email ?? '',
    avatar: props.initialProfile?.avatar ?? (props.avatarOptions[0] ?? ''),
    role: props.initialProfile?.role ?? '',
    emailNotifications: props.initialProfile?.emailNotifications ?? false,
    theme: props.initialProfile?.theme ?? 'light',
  });
  const [errors, setErrors] = useState<Errors>({});

  useEffect(() => {
    setErrors({});
  }, [currentStep]);

  const validateEmail = (email: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  };

  const validateStep1 = (): boolean => {
    const newErrors: Errors = {};

    if (!formData.name || formData.name.length < 2) {
      newErrors.name =
        formData.name.length === 0
          ? 'Name is required'
          : 'Name must be at least 2 characters';
    }

    if (!formData.email) {
      newErrors.email = 'Email is required';
    } else if (!validateEmail(formData.email)) {
      newErrors.email = 'Please enter a valid email address';
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const validateStep2 = (): boolean => {
    const newErrors: Errors = {};

    if (!formData.role) {
      newErrors.name = 'Role is required';
    }

    setErrors(newErrors as Errors);
    return Object.keys(newErrors).length === 0;
  };

  const updateFormData = (updates: Partial<FormData>) => {
    setFormData((prev) => ({ ...prev, ...updates }));
  };

  const handleNext = () => {
    if (currentStep === 1) {
      if (validateStep1()) {
        setCurrentStep(2);
      }
    } else if (currentStep === 2) {
      if (validateStep2()) {
        setCurrentStep(3);
      }
    }
  };

  const handleBack = () => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  };

  const handleComplete = () => {
    if (props.onComplete) {
      props.onComplete({
        name: formData.name,
        email: formData.email,
        avatar: formData.avatar,
        role: formData.role,
        emailNotifications: formData.emailNotifications,
        theme: formData.theme,
      });
    }
  };

  const progressValue = (currentStep / 3) * 100;

  const roleOptions = props.roleOptions.map((role) => ({
    value: role,
    label: role,
  }));

  return (
    <Container maxWidth="lg" padding={24}>
      <Stack gap={24}>
        {/* Step Indicator */}
        <Stack gap={12}>
          <Stack
            direction="horizontal"
            justify="between"
            align="center"
            gap={8}
          >
            <Text variant="label">Step {currentStep} of 3</Text>
          </Stack>
          <Progress
            value={progressValue}
            max={100}
            variant="default"
            size="sm"
          />
        </Stack>

        {/* Step Content */}
        <Card shadow="md" padding={24} key={`step-${currentStep}`}>
          {currentStep === 1 && (
            <Stack gap={16}>
              <Heading level={4}>Profile Setup</Heading>

              <Input
                label="Name"
                value={formData.name}
                onChange={(value) => updateFormData({ name: value })}
                placeholder="Enter your name"
                error={errors.name}
                required
              />

              <Input
                label="Email"
                type="email"
                value={formData.email}
                onChange={(value) => updateFormData({ email: value })}
                placeholder="Enter your email"
                error={errors.email}
                required
              />

              <Stack gap={8}>
                <Text variant="label">Choose Avatar</Text>
                <Stack
                  direction="horizontal"
                  gap={12}
                  align="center"
                  wrap={true}
                >
                  {props.avatarOptions.map((emoji) => (
                    <Box
                      key={emoji}
                      padding={12}
                      borderRadius={8}
                      background={
                        formData.avatar === emoji
                          ? 'var(--ggui-color-primary-600, #0284c7)'
                          : 'var(--ggui-color-outline, #d4d4d8)'
                      }
                      style={{
                        cursor: 'pointer',
                        fontSize: '32px',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        width: '56px',
                        height: '56px',
                        transition: 'all 200ms ease',
                      }}
                      onClick={() => updateFormData({ avatar: emoji })}
                    >
                      {emoji}
                    </Box>
                  ))}
                </Stack>
              </Stack>
            </Stack>
          )}

          {currentStep === 2 && (
            <Stack gap={16}>
              <Heading level={4}>Preferences</Heading>

              <Select
                label="Role"
                value={formData.role}
                onChange={(value) => updateFormData({ role: value })}
                options={roleOptions}
                placeholder="Select a role"
                required
              />

              <Stack direction="horizontal" align="center" gap={12}>
                <Text variant="label">Email Notifications</Text>
                <Toggle
                  label=""
                  checked={formData.emailNotifications}
                  onChange={(checked) =>
                    updateFormData({ emailNotifications: checked })
                  }
                  size="md"
                />
              </Stack>

              <Stack direction="horizontal" align="center" gap={12}>
                <Text variant="label">Dark Theme</Text>
                <Toggle
                  label=""
                  checked={formData.theme === 'dark'}
                  onChange={(checked) =>
                    updateFormData({ theme: checked ? 'dark' : 'light' })
                  }
                  size="md"
                />
              </Stack>
            </Stack>
          )}

          {currentStep === 3 && (
            <Stack gap={16}>
              <Heading level={4}>Review Your Profile</Heading>

              <Stack gap={12}>
                <Stack
                  direction="horizontal"
                  justify="between"
                  gap={8}
                  align="center"
                >
                  <Text variant="label">Name</Text>
                  <Text variant="body">{formData.name}</Text>
                </Stack>
                <Divider margin={8} />

                <Stack
                  direction="horizontal"
                  justify="between"
                  gap={8}
                  align="center"
                >
                  <Text variant="label">Email</Text>
                  <Text variant="body">{formData.email}</Text>
                </Stack>
                <Divider margin={8} />

                <Stack
                  direction="horizontal"
                  justify="between"
                  gap={8}
                  align="center"
                >
                  <Text variant="label">Avatar</Text>
                  <Text variant="body" style={{ fontSize: '24px' }}>
                    {formData.avatar}
                  </Text>
                </Stack>
                <Divider margin={8} />

                <Stack
                  direction="horizontal"
                  justify="between"
                  gap={8}
                  align="center"
                >
                  <Text variant="label">Role</Text>
                  <Text variant="body">{formData.role}</Text>
                </Stack>
                <Divider margin={8} />

                <Stack
                  direction="horizontal"
                  justify="between"
                  gap={8}
                  align="center"
                >
                  <Text variant="label">Email Notifications</Text>
                  <Text variant="body">
                    {formData.emailNotifications ? 'Enabled' : 'Disabled'}
                  </Text>
                </Stack>
                <Divider margin={8} />

                <Stack
                  direction="horizontal"
                  justify="between"
                  gap={8}
                  align="center"
                >
                  <Text variant="label">Theme</Text>
                  <Text variant="body">
                    {formData.theme.charAt(0).toUpperCase() +
                      formData.theme.slice(1)}
                  </Text>
                </Stack>
              </Stack>
            </Stack>
          )}
        </Card>

        {/* Navigation Buttons */}
        <Stack
          direction="horizontal"
          justify="between"
          align="center"
          gap={8}
        >
          <Button
            variant="ghost"
            onClick={handleBack}
            disabled={currentStep === 1}
          >
            Back
          </Button>

          {currentStep < 3 ? (
            <Button
              variant="primary"
              onClick={handleNext}
              disabled={
                (currentStep === 1 && Object.keys(errors).length > 0) ||
                (currentStep === 2 && !formData.role)
              }
            >
              Next
            </Button>
          ) : (
            <Button variant="primary" onClick={handleComplete}>
              Complete Setup
            </Button>
          )}
        </Stack>
      </Stack>
    </Container>
  );
}
